import { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';

import BaseTamplate from '../consts/BaseTamplate';
import { readRows, getRow, deleteRow } from '../../consts/crud';


function Roads() {
    const [tableData, setTableData] = useState([]);
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const fetchTableData = useCallback(async () => {
        setLoading(true);

        const read_roads = await readRows('/roads');
        setTableData(Array.isArray(read_roads) ? read_roads : [read_roads]);

        setLoading(false);
    }, []);

    useEffect(() => {
        fetchTableData();
    }, [fetchTableData]);

    return (
        <div> 
            {loading ? (
                <div>
                    <p>Загрузка данных...</p>
                </div>
            ) : tableData.length > 0 ? (
                <div>
                    <BaseTamplate />
                    <div className='container'>
                        <p className='Table-header'><h1>Дороги.</h1></p>
                        <table className='table table-striped'>
                            <thead>
                                <tr>
                                    <th scope='col'>ID</th>
                                    <th scope='col'>Название дороги</th>
                                    <th scope='col'>Номер дороги</th>
                                    <th scope='col'>
                                        Операции  
                                        <button type='button' className='btn btn-success btn-sm me-1' onClick={() => navigate('/road/add')}>
                                            Создать
                                        </button>
                                    </th>
                                </tr>
                            </thead>
                            <tbody>
                                {tableData[0]?.items.map((road) =>(
                                    <tr key={road.id}>
                                        <th>{road.id}</th>
                                        <td>{road.name_road}</td>
                                        <td>{road.number_road}</td>
                                        <td>
                                            <button type='button' className='btn btn-primary btn-sm me-1' onClick={() => { getRow('/road', road.id); navigate(`/road/edit/${road.id}`);}}>
                                                Редактировать
                                            </button>
                                            <button type='button' className='btn btn-danger btn-sm' onClick={() => { deleteRow('/roads', road.id); fetchTableData(); }}> {/* Поправить */}
                                                Удалить
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            ) : (
                <p className='no-data'>Нет данных для отображения</p> 
            )} 
        </div>
    );
}

export default Roads;
